#include <bits/stdc++.h>
using namespace std;
bool num[9];
bool check(int d,int e,int f)
{
	for(int i=0;i<=8;i++)
	{
		num[i]=false;
	}
    for(int i=1;i<=3;i++)
    {
        if(!(num[d%10-1]))
        {
            num[d%10-1]=true;
            d/=10;
        }
        else
        {
            return false;
        }
        if(!(num[e%10-1]))
        {
            num[e%10-1]=true;
            e/=10;
        }
        else
        {
            return false;
        }
        if(!(num[f%10-1]))
        {
            num[f%10-1]=true;
            f/=10;
        }
        else
        {
            return false;
        }
    }
    return true;
}
int main()
{
    int a,b,c,A,B,C;
    bool flag=false;
    cin>>A>>B>>C;
    for(a=123;a<=987/C*A;a++)
    {
        b=a/A*B;
        c=a/A*C;
        if(check(a,b,c))
        {
            cout<<a<<" "<<b<<" "<<c<<endl;
            flag=true;
        }
    }
    if(flag==false)
    {
    	cout<<"No!!!";
	}
    return 0;
}
